query:
SELECT COUNT(*) AS total_quick_notes FROM quick_notes;
SELECT COUNT(*) AS notes_this_week FROM quick_notes WHERE createdAt >= DATE_SUB(NOW(), INTERVAL 7 DAY);
SELECT COUNT(*) AS roundups_this_week FROM weekly_roundups WHERE createdAt >= DATE_SUB(NOW(), INTERVAL 7 DAY);
SELECT quick_notes FROM weekly_roundups ORDER BY createdAt DESC LIMIT 1;

